import{_ as o,o as t,c as i,a3 as a}from"./chunks/framework.BTFg6ESq.js";const g=JSON.parse('{"title":"技术备忘：Chromium 149+ Windows 中文输入首次丢失 Bug 与应对方案","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/chromium-149-ime-bug.md","filePath":"architecture/chromium-149-ime-bug.md","lastUpdated":1781157246000}'),r={name:"architecture/chromium-149-ime-bug.md"};function s(n,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="技术备忘-chromium-149-windows-中文输入首次丢失-bug-与应对方案" tabindex="-1">技术备忘：Chromium 149+ Windows 中文输入首次丢失 Bug 与应对方案 <a class="header-anchor" href="#技术备忘-chromium-149-windows-中文输入首次丢失-bug-与应对方案" aria-label="Permalink to &quot;技术备忘：Chromium 149+ Windows 中文输入首次丢失 Bug 与应对方案&quot;">​</a></h1><h2 id="_1-背景与问题概述" tabindex="-1">1. 背景与问题概述 <a class="header-anchor" href="#_1-背景与问题概述" aria-label="Permalink to &quot;1. 背景与问题概述&quot;">​</a></h2><p>在 Windows 平台下，当应用升级或运行在 <strong>Chromium 149.0.7827.103 及以上版本</strong>（包括 Google Chrome 149+、Microsoft Edge 149+ 以及未来基于此内核的 Tauri/Electron 运行时）时，用户在使用中文输入法（IME）向基于 <code>contenteditable</code> 的编辑器（如 <strong>CodeMirror 6</strong>）输入内容时，会遇到<strong>首次合成输入被静默丢弃</strong>的严重 Bug。</p><h3 id="典型症状" tabindex="-1">典型症状 <a class="header-anchor" href="#典型症状" aria-label="Permalink to &quot;典型症状&quot;">​</a></h3><ol><li><strong>中文标点需要输入两次</strong>：使用微软拼音输入法时，输入中文标点（如 <code>。</code>、<code>，</code>、<code>：</code>）时，第一次按键编辑器无任何反应，必须紧接着再按一次（可以是不同标点）才会输出第二次按下的标点。</li><li><strong>第三方输入法（如 QQ 拼音）汉字丢失</strong>：使用 QQ 拼音输入汉字时，第一次拼写并选择候选词后，编辑器中什么都不会出现（首次合成完全丢失）；第二次拼写才能正常上屏。</li><li><strong>原生 <code>textarea</code> 和 <code>input</code> 元素完全不受影响</strong>。</li></ol><hr><h2 id="_2-根因分析与测试证据" tabindex="-1">2. 根因分析与测试证据 <a class="header-anchor" href="#_2-根因分析与测试证据" aria-label="Permalink to &quot;2. 根因分析与测试证据&quot;">​</a></h2><p>通过在项目中引入 <a href="./../../src/tools/component-tester/components/IMEInputTester.vue"><code>IMEInputTester.vue</code></a> 进行深度事件捕获，我们获取了该 Bug 在浏览器底层的关键行为特征：</p><h3 id="_2-1-关键发现-首次合成事件被浏览器静默抑制" tabindex="-1">2.1 关键发现：首次合成事件被浏览器静默抑制 <a class="header-anchor" href="#_2-1-关键发现-首次合成事件被浏览器静默抑制" aria-label="Permalink to &quot;2.1 关键发现：首次合成事件被浏览器静默抑制&quot;">​</a></h3><p>在受影响的 Chromium 版本中，当用户在 <code>contenteditable</code> 元素上进行<strong>第一次 IME 合成输入</strong>时：</p><ul><li>浏览器<strong>完全不派发</strong> <code>compositionstart</code>、<code>beforeinput</code>、<code>input</code>、<code>compositionend</code> 等任何 IME 相关的 JS 事件。</li><li>键盘事件中，<code>keydown</code> 事件被静默吞噬（不触发），但合成结束后的 <code>keyup</code> 事件却能正常到达 JS 层。</li><li>由于没有任何输入事件到达 DOM 和编辑器框架，JavaScript 层面（包括 React、Vue、CodeMirror 核心）完全无法感知到这次输入，导致内容彻底丢失。</li><li>从<strong>第二次合成输入</strong>开始，所有事件恢复正常派发。</li></ul><h3 id="_2-2-跨浏览器对比验证" tabindex="-1">2.2 跨浏览器对比验证 <a class="header-anchor" href="#_2-2-跨浏览器对比验证" aria-label="Permalink to &quot;2.2 跨浏览器对比验证&quot;">​</a></h3><p>该问题已被确认为 <strong>Chromium 引擎级回归 Bug</strong>，而非前端框架或编辑器库的问题：</p><ul><li><strong>受影响</strong>：Google Chrome 149.0.7827.102+、Microsoft Edge 149.0.4022.62+（从 149.0.4022.52 升级内核后立即出现）。</li><li><strong>不受影响</strong>：Firefox 150+、旧版 Edge (Chromium 149.0.7827.54 之前)、Electron (Chromium 142) 等。</li></ul><hr><h2 id="_3-aio-hub-的应对与降级方案-workaround" tabindex="-1">3. AIO Hub 的应对与降级方案 (Workaround) <a class="header-anchor" href="#_3-aio-hub-的应对与降级方案-workaround" aria-label="Permalink to &quot;3. AIO Hub 的应对与降级方案 (Workaround)&quot;">​</a></h2><p>由于该 Bug 发生在浏览器内核的事件派发阶段，在 JavaScript 层面<strong>无法通过任何黑魔法（如模拟事件、强制刷新、合成锁延迟等）在 <code>contenteditable</code> 上完美修复</strong>。</p><p>为了保证 AIO Hub 核心聊天功能在 Windows 平台下的可用性，我们实现了一套<strong>原生 <code>textarea</code> 降级方案</strong>。</p><h3 id="_3-1-核心设计" tabindex="-1">3.1 核心设计 <a class="header-anchor" href="#_3-1-核心设计" aria-label="Permalink to &quot;3.1 核心设计&quot;">​</a></h3><p>我们允许用户在聊天输入框中一键切换使用<strong>原生 <code>textarea</code></strong> 替代 <strong>CodeMirror 6</strong>。因为原生 <code>textarea</code> 不走 <code>contenteditable</code> 路径，完全不受此 Chromium Bug 影响。</p><h3 id="_3-2-模块实现结构" tabindex="-1">3.2 模块实现结构 <a class="header-anchor" href="#_3-2-模块实现结构" aria-label="Permalink to &quot;3.2 模块实现结构&quot;">​</a></h3><ol><li><p><strong>新增原生编辑器组件</strong>：<a href="./../../src/tools/llm-chat/components/message-input/ChatTextareaEditor.vue"><code>ChatTextareaEditor.vue</code></a></p><ul><li>采用原生 <code>&lt;textarea&gt;</code> 实现。</li><li>封装并暴露了与 <a href="./../../src/tools/llm-chat/components/message-input/ChatCodeMirrorEditor.vue"><code>ChatCodeMirrorEditor.vue</code></a> <strong>完全一致的接口方法</strong>： <ul><li><code>focus()</code></li><li><code>setSelectionRange(start, end)</code></li><li><code>getSelectionRange()</code></li><li><code>insertText(text)</code></li><li><code>replaceRange(text, from, to)</code></li><li><code>getValue()</code></li></ul></li><li>完美兼容原有的快捷键发送逻辑（如 <code>Ctrl+Enter</code> 发送、单 <code>Enter</code> 换行等）和粘贴/拖拽附件逻辑。</li></ul></li><li><p><strong>配置项扩展</strong>：<a href="../../src/tools/llm-chat/types/settings.ts"><code>settings.ts</code></a></p><ul><li>在 <code>uiPreferences</code> 中新增 <code>useNativeTextarea: boolean</code> 字段（默认 <code>false</code>）。</li></ul></li><li><p><strong>动态切换桥接</strong>：<a href="./../../src/tools/llm-chat/components/message-input/MessageInput.vue"><code>MessageInput.vue</code></a></p><ul><li>根据 <code>settings.uiPreferences.useNativeTextarea</code> 动态挂载对应的编辑器组件：<div class="language-vue vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">ChatTextareaEditor</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  v-if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">settings.uiPreferences.useNativeTextarea</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  ref</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;editorRef&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;ChatCodeMirrorEditor v-else ref=&quot;editorRef&quot; ... /&gt;</span></span></code></pre></div></li></ul></li><li><p><strong>UI 快捷开关</strong>：</p><ul><li><strong>工具栏快捷入口</strong>：在聊天输入框工具栏的齿轮设置弹窗 (<a href="./../../src/tools/llm-chat/components/message-input/toolbar/ToolbarSettingsPopover.vue"><code>ToolbarSettingsPopover.vue</code></a>) 底部，增加「使用原生输入框」开关，并附带 Tooltip 解释该开关用于规避 Chromium 149+ 的中文输入 Bug。</li><li><strong>全局设置页</strong>：在聊天设置的「界面偏好」分区 (<a href="../../src/tools/llm-chat/components/settings/settingsConfig.ts"><code>settingsConfig.ts</code></a>) 中同步提供该开关。</li></ul></li></ol><hr><h2 id="_4-长期跟进建议" tabindex="-1">4. 长期跟进建议 <a class="header-anchor" href="#_4-长期跟进建议" aria-label="Permalink to &quot;4. 长期跟进建议&quot;">​</a></h2><ol><li><strong>关注上游修复</strong>： <ul><li>持续跟踪 <a href="https://discuss.codemirror.net/t/chinese-ime-punctuation-input-loses-every-other-keypress-requires-2-presses-per-character/9741" target="_blank" rel="noreferrer">CodeMirror 官方论坛讨论帖</a> 以及 Chromium Bug Tracker。</li><li>一旦 Chromium 官方发布修复版本，或 CodeMirror 层面探索出针对该内核版本的特定绕过补丁，我们将评估是否可以默认切回 CodeMirror 6。</li></ul></li><li><strong>保持 <code>ChatTextareaEditor</code> 与 <code>ChatCodeMirrorEditor</code> 的接口对齐</strong>： <ul><li>后续若对聊天输入框有功能扩展（如新增特定的命令补全、@ 成员等富文本交互），需同时在两个编辑器组件中做好适配或降级处理。</li></ul></li></ol>`,25)])])}const p=o(r,[["render",s]]);export{g as __pageData,p as default};
